// --- src/codegen/ts-generator.ts ---
import path from "path";
import fs from "fs/promises";
/**
 * Generates the final user-facing client.ts file.
 * @param outputDir The directory to write the file to.
 * @param schema The processed schema from the config.
 */
export async function generateClient(outputDir, schema) {
    // This is a placeholder for now. We will implement the actual
    // client generation in the next step.
    const content = `
// Generated by @zgdb/cli.
// This is a placeholder. The real client will be generated in the next step.

import { PTree } from 'prolly-gunna';

export function createClient(ptree?: PTree) {
    console.log("Initializing zgdb client...");
    const db = ptree || new PTree();
    // TODO: The real client logic will go here.
    return {
        // The real collections will be proxies.
        user: new Map(),
        post: new Map(),
        tag: new Map(),
        _db: db
    };
}
`;
    const filePath = path.join(outputDir, "client.ts");
    await fs.writeFile(filePath, content, "utf8");
}
